import type { NextPage } from "next";
import { useEffect, useRef } from "react";
import * as THREE from "three";

import { ZenGardenScene } from "@/zen-garden-v2/scene";

const ZenGardenV2Page: NextPage = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Renderer
    const renderer = new THREE.WebGLRenderer({ canvas, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(window.devicePixelRatio);

    // Camera looking down
    const camera = new THREE.PerspectiveCamera(
      60,
      window.innerWidth / window.innerHeight,
      0.1,
      1000
    );
    camera.position.set(0, 10, 0);
    camera.lookAt(0, 0, 0);

    // Scene with some test objects
    const gardenScene = new ZenGardenScene({
      objects: [
        { id: "rock1", type: "rock", position: { x: -1, y: 0 } },
        { id: "rock2", type: "rock", position: { x: 1, y: 1 } },
        { id: "moss1", type: "moss", polygonPath: [
          { x: -2, y: -2 },
          { x: -1, y: -2 },
          { x: -1, y: -1 },
          { x: -2, y: -1 },
        ]},
      ],
    });

    // Light
    const ambient = new THREE.AmbientLight(0xffffff, 0.5);
    gardenScene.threeScene.add(ambient);

    const sun = new THREE.DirectionalLight(0xffffff, 1);
    sun.position.set(5, 10, 5);
    gardenScene.threeScene.add(sun);

    // Animation loop
    let disposed = false;
    const animate = () => {
      if (disposed) return;
      requestAnimationFrame(animate);
      renderer.render(gardenScene.threeScene, camera);
    };
    animate();

    // Resize handler
    const handleResize = () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      disposed = true;
      window.removeEventListener("resize", handleResize);
      renderer.dispose();
    };
  }, []);

  return <canvas ref={canvasRef} className="w-full h-full" />;
};

export default ZenGardenV2Page;
